mapper.insert:
INSERT INTO t_document_chunk (
    document_id, knowledge_id, chunk_index, content,
    token_count, content_hash, milvus_id, metadata_json, created_at
) VALUES (
    #{documentId}, #{knowledgeId}, #{chunkIndex}, #{content},
    #{tokenCount}, #{contentHash}, #{milvusId}, #{metadataJson}, #{createdAt}
)

mapper.select:
SELECT id, document_id, knowledge_id, chunk_index, content,
       token_count, content_hash, milvus_id, metadata_json, created_at
FROM t_document_chunk
WHERE document_id = #{documentId}
ORDER BY chunk_index ASC
LIMIT #{limit} OFFSET #{offset}
